begin;
create extension if not exists pgcrypto;

create or replace function public.revenue_os_touch_updated_at()
returns trigger language plpgsql as $$
begin new.updated_at = timezone('utc', now()); return new; end $$;

create table if not exists public.revenue_os_business_units (
  id uuid primary key default gen_random_uuid(), code text not null unique, name text not null, tagline text not null default '',
  purpose text not null default '', revenue_model text not null default '', delivery_model text not null default '', owner_role text not null default '',
  status text not null default 'needs-validation' check (status in ('draft','needs-validation','validated','active','inactive','retired')),
  commercial_priority integer not null default 50 check (commercial_priority between 0 and 100), active_offers integer not null default 0,
  target_segments integer not null default 0, territories jsonb not null default '[]'::jsonb, dependencies jsonb not null default '[]'::jsonb,
  source text not null default 'manual', metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default timezone('utc', now()), updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.revenue_os_offer_families (
