  name text not null, description text not null default '', commercial_role text not null default '', status text not null default 'active',
  created_at timestamptz not null default timezone('utc', now()), updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.revenue_os_offers (
  id uuid primary key default gen_random_uuid(), code text not null unique, business_unit_code text not null references public.revenue_os_business_units(code) on update cascade,
  family text not null default '', name text not null, commercial_name text not null, customer_problem text not null default '', value_proposition text not null default '',
  delivery_formats jsonb not null default '[]'::jsonb, target_segment_codes jsonb not null default '[]'::jsonb, decision_maker_codes jsonb not null default '[]'::jsonb,
  territory_codes jsonb not null default '[]'::jsonb, sales_cycle_days integer not null default 0, pricing_model text not null default '',
  price_from_dh numeric(14,2), price_to_dh numeric(14,2), target_margin_pct numeric(7,2), max_discount_pct numeric(7,2),
  required_capacity_codes jsonb not null default '[]'::jsonb, evidence_assets jsonb not null default '[]'::jsonb,
  status text not null default 'needs-validation' check (status in ('draft','needs-validation','validated','active','inactive','retired')),
  availability text not null default 'conditional' check (availability in ('available','conditional','unavailable','planned')),
  source text not null default 'manual', metadata jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default timezone('utc', now()), updated_at timestamptz not null default timezone('utc', now())
);

