-- Updated-at triggers
DO $$
DECLARE t text;
BEGIN
  FOREACH t IN ARRAY ARRAY[
    'revenue_os_business_units','revenue_os_offer_families','revenue_os_offers','revenue_os_offer_formats','revenue_os_offer_bundles',
    'revenue_os_offer_relationships','revenue_os_customer_segments','revenue_os_segment_offer_fit','revenue_os_decision_maker_profiles',
    'revenue_os_regions','revenue_os_cities','revenue_os_territories','revenue_os_markets','revenue_os_offer_territory_availability',
    'revenue_os_sales_channels','revenue_os_sales_journeys','revenue_os_sales_journey_stages','revenue_os_price_books','revenue_os_pricing_models',
    'revenue_os_offer_prices','revenue_os_cost_models','revenue_os_margin_rules','revenue_os_discount_rules','revenue_os_capacity_types',
    'revenue_os_delivery_constraints','revenue_os_revenue_dependencies','revenue_os_seasonal_windows','revenue_os_growth_paths',
    'revenue_os_digital_twin_gaps','revenue_os_model_owners','revenue_os_model_approval_requests'
  ]
  LOOP
    EXECUTE format('drop trigger if exists %I_touch_updated_at on public.%I', t, t);
    EXECUTE format('create trigger %I_touch_updated_at before update on public.%I for each row execute function public.revenue_os_touch_updated_at()', t, t);
  END LOOP;
END $$;

-- Phase 2 permissions/workspace/flags are cumulative over Phase 1.
