values ('digital-twin','Jumeau commercial','Digital Twin','Modèle commercial vivant des unités, offres, segments, décideurs, marchés, prix, capacités, parcours et chemins de croissance AngelCare.','/revenue-command-os/digital-twin','Network',20,'revenue_os.digital_twin.manage','ready','cyan','["Business units","Offres","Segments","Décideurs","Territoires","Prix","Capacités","Parcours","Dépendances","Validation"]'::jsonb,true)
on conflict (workspace_key) do update set label=excluded.label, short_label=excluded.short_label, description=excluded.description, href=excluded.href, icon=excluded.icon, display_order=excluded.display_order, permission_key=excluded.permission_key, maturity_status=excluded.maturity_status, accent=excluded.accent, contract_scope=excluded.contract_scope, active=true, updated_at=timezone('utc',now());

update public.revenue_os_workspaces set display_order = case workspace_key
  when 'revenue-objectives' then 30 when 'signals' then 40 when 'strategies' then 50 when 'intelligent-commands' then 60
  when 'active-programs' then 70 when 'compiled-missions' then 80 when 'approvals' then 90 when 'exceptions' then 100
  when 'memory-learning' then 110 when 'audit' then 120 when 'settings' then 130 else display_order end
where workspace_key <> 'digital-twin';

