insert into public.revenue_os_sales_journeys(code,name,business_unit_codes,segment_codes,offer_codes,objective,stages,status) values ('JRN-FLASHCARDS-PARTNER','Flashcards PLV — Point partenaire vers réassort','["BU-FLASHCARDS"]'::jsonb,'["SEG-PRESCHOOL-PRIVATE","SEG-MATERNITY","SEG-ORTHOPHONISTS"]'::jsonb,'["OFF-FLASHCARDS-PLV"]'::jsonb,'Installer un point partenaire actif et déclencher des cycles de réassort.','[{"code":"FCP-QUALIFY","name":"Qualifier le point","order":1,"entryCriteria":["Organisation identifiée"],"exitCriteria":["Potentiel et espace PLV validés"],"requiredData":["Type","Ville","Décideur"],"requiredEvidence":["Notes"],"responsibleRole":"Technico-commercial","maximumRecommendedDays":3,"successEvent":"revenue.flashcards.partner.qualified","failureEvent":"revenue.flashcards.partner.disqualified","recoveryRoute":"Reclasser ou nourrir."},{"code":"FCP-PRESENT","name":"Présenter le programme","order":2,"entryCriteria":["Point qualifié"],"exitCriteria":["Intérêt et conditions enregistrés"],"requiredData":["Collections","Conditions"],"requiredEvidence":["Catalogue envoyé"],"responsibleRole":"Technico-commercial","maximumRecommendedDays":5,"successEvent":"revenue.flashcards.program.presented","failureEvent":"revenue.flashcards.program.no_response","recoveryRoute":"Relance multicanale."},{"code":"FCP-ORDER","name":"Commande initiale","order":3,"entryCriteria":["Accord commercial"],"exitCriteria":["Commande et paiement validés"],"requiredData":["Quantités","Adresse"],"requiredEvidence":["Bon de commande"],"responsibleRole":"Commercial / Finance","maximumRecommendedDays":10,"successEvent":"revenue.flashcards.order.confirmed","failureEvent":"revenue.flashcards.order.stalled","recoveryRoute":"Clarifier objection ou condition."},{"code":"FCP-INSTALL","name":"Installation PLV","order":4,"entryCriteria":["Commande prête"],"exitCriteria":["PLV installée"],"requiredData":["Date","Contact site"],"requiredEvidence":["Photo / confirmation"],"responsibleRole":"Opérations","maximumRecommendedDays":7,"successEvent":"revenue.flashcards.plv.installed","failureEvent":"revenue.flashcards.delivery.blocked","recoveryRoute":"Mission logistique."},{"code":"FCP-REPLENISH","name":"Réassort","order":5,"entryCriteria":["Point actif"],"exitCriteria":["Besoin réassort évalué"],"requiredData":["Stock","Ventes"],"requiredEvidence":["Commande ou report"],"responsibleRole":"Relation partenaires","maximumRecommendedDays":30,"successEvent":"revenue.flashcards.replenishment.created","failureEvent":"revenue.flashcards.partner.inactive","recoveryRoute":"Réactivation partenaire."}]'::jsonb,'active') on conflict (code) do update set name=excluded.name, business_unit_codes=excluded.business_unit_codes, segment_codes=excluded.segment_codes, offer_codes=excluded.offer_codes, objective=excluded.objective, stages=excluded.stages, status=excluded.status, updated_at=timezone('utc',now());
insert into public.revenue_os_sales_journeys(code,name,business_unit_codes,segment_codes,offer_codes,objective,stages,status) values ('JRN-HOME-SERVICE','Home Service — Besoin famille vers mission récurrente','["BU-HOME-SERVICE"]'::jsonb,'["SEG-FAMILIES-PREMIUM"]'::jsonb,'["OFF-HOME-ON-DEMAND","OFF-HOME-RECURRING","OFF-HOME-HOLIDAY"]'::jsonb,'Qualifier, sécuriser, convertir et développer une relation de garde durable.','[{"code":"HS-REQUEST","name":"Demande reçue","order":1,"entryCriteria":["Contact entrant"],"exitCriteria":["Besoin minimum documenté"],"requiredData":["Ville","Date","Enfant","Durée"],"requiredEvidence":["Demande"],"responsibleRole":"Relation clients","maximumRecommendedDays":1,"successEvent":"revenue.home.request.qualified","failureEvent":"revenue.home.request.incomplete","recoveryRoute":"Collecter données manquantes."},{"code":"HS-MATCH","name":"Faisabilité & matching","order":2,"entryCriteria":["Besoin qualifié"],"exitCriteria":["Capacité et agent disponibles"],"requiredData":["Disponibilité","Zone"],"requiredEvidence":["Réservation capacité"],"responsibleRole":"Dispatch","maximumRecommendedDays":1,"successEvent":"revenue.home.capacity.reserved","failureEvent":"revenue.home.capacity.unavailable","recoveryRoute":"Alternative horaire ou liste d’attente."},{"code":"HS-CONFIRM","name":"Confirmation & paiement","order":3,"entryCriteria":["Faisabilité confirmée"],"exitCriteria":["Mission confirmée"],"requiredData":["Prix","Conditions"],"requiredEvidence":["Confirmation"],"responsibleRole":"Relation clients / Finance","maximumRecommendedDays":2,"successEvent":"revenue.home.mission.confirmed","failureEvent":"revenue.home.payment.pending","recoveryRoute":"Relance ou annulation contrôlée."},{"code":"HS-DELIVER","name":"Mission exécutée","order":4,"entryCriteria":["Mission confirmée"],"exitCriteria":["Rapport et qualité validés"],"requiredData":["Présence","Rapport"],"requiredEvidence":["Preuve mission"],"responsibleRole":"Opérations","maximumRecommendedDays":2,"successEvent":"revenue.home.mission.completed","failureEvent":"revenue.home.mission.incident","recoveryRoute":"Incident / service recovery."},{"code":"HS-EXPAND","name":"Récurrence & recommandation","order":5,"entryCriteria":["Mission réussie"],"exitCriteria":["Prochaine opportunité qualifiée"],"requiredData":["Satisfaction","Besoin futur"],"requiredEvidence":["Feedback"],"responsibleRole":"Customer success","maximumRecommendedDays":7,"successEvent":"revenue.home.expansion.created","failureEvent":"revenue.home.no_followup","recoveryRoute":"Relance satisfaction."}]'::jsonb,'active') on conflict (code) do update set name=excluded.name, business_unit_codes=excluded.business_unit_codes, segment_codes=excluded.segment_codes, offer_codes=excluded.offer_codes, objective=excluded.objective, stages=excluded.stages, status=excluded.status, updated_at=timezone('utc',now());
