-- RLS and server-only access. The application server uses the service role; browser clients receive no direct rights.
DO $$
DECLARE t text;
BEGIN
  FOREACH t IN ARRAY ARRAY[
    'revenue_os_business_units','revenue_os_offer_families','revenue_os_offers','revenue_os_offer_versions','revenue_os_offer_formats',
    'revenue_os_offer_bundles','revenue_os_offer_bundle_items','revenue_os_offer_relationships','revenue_os_customer_segments',
    'revenue_os_segment_needs','revenue_os_segment_pain_points','revenue_os_segment_offer_fit','revenue_os_decision_maker_profiles',
    'revenue_os_regions','revenue_os_cities','revenue_os_territories','revenue_os_markets','revenue_os_offer_territory_availability',
    'revenue_os_sales_channels','revenue_os_sales_journeys','revenue_os_sales_journey_stages','revenue_os_stage_requirements',
    'revenue_os_price_books','revenue_os_pricing_models','revenue_os_offer_prices','revenue_os_cost_models','revenue_os_margin_rules',
    'revenue_os_discount_rules','revenue_os_capacity_types','revenue_os_capacity_requirements','revenue_os_delivery_constraints',
    'revenue_os_revenue_dependencies','revenue_os_seasonal_windows','revenue_os_growth_paths','revenue_os_cross_sell_paths',
    'revenue_os_upsell_paths','revenue_os_renewal_paths','revenue_os_referral_paths','revenue_os_digital_twin_validations',
    'revenue_os_digital_twin_gaps','revenue_os_digital_twin_versions','revenue_os_digital_twin_change_log','revenue_os_model_owners',
    'revenue_os_model_approval_requests'
  ]
  LOOP
    EXECUTE format('alter table public.%I enable row level security', t);
    EXECUTE format('revoke all on table public.%I from anon, authenticated', t);
  END LOOP;
END $$;

commit;
